public class Rectangle {
    private int width;
    private int height;

    public Rectangle(int width, int height) {
        width = width;
        height = height;
    }

    public String toString() {
        return "width=" + width + ", height=" + height;
    }

    public static void main(String[] args) {
        Rectangle r = new Rectangle(10, 5);
        System.out.println(r);
    }
}
